#!/usr/bin/env python3
# patch_v358_daily_squeeze_long_only.py
# ---------------------------------------------------------------------------
# v358 — gate `_check_daily_squeeze` to LONG-ONLY (suppress the momentum-short branch).
#
# EVIDENCE (diag_v358_daily_squeeze_replay.py, 365d / 400-sym daily IB bars):
#   The setup is a LONG-only edge — SHORT loses in EVERY config tested:
#     | config                 | LONG winsorAvg / totW | SHORT winsorAvg / totW |
#     | compression/±10% (LIVE)| +0.073 / +1532.7      | -0.056 / -1067.1       |
#     | release/±10%           | +0.053 / +396.5       | -0.071 / -452.7        |
#     | compression/2.5ATR     | +0.061 / +1287.5      | -0.041 / -789.9        |
#     | release/2.5ATR         | +0.047 / +348.1       | -0.072 / -455.7        |
#     | tight0.5 / hold20      | +0.083 / +889.5       | -0.088 / -846.2        |
#   The momentum-short branch (shorting a daily squeeze in a drift-up tape) drags a solidly
#   +EV long side to breakeven. Fix = keep the long edge, suppress shorts. Geometry unchanged
#   (compression + ±10% target is already the best long config).
#
# Anchored-chunk patcher (AGENTS.md §2): whole-file PRE-SHA guard + exact OLD-bytes match
# (count MUST be 1) + post-write self-verify. ABORTS before writing on ANY drift. Backs up
# the original. Supports --check dry-run. Only inserts a `if direction != "long": return None`
# gate right after the direction is computed; nothing else changes.
#
# Deploy (DGX, repo root):
#   curl -sS -o /tmp/patch_v358.py https://paste.rs/<id>
#   .venv/bin/python /tmp/patch_v358.py --check
#   .venv/bin/python /tmp/patch_v358.py
#   .venv/bin/python -m pytest backend/tests/test_v358_daily_squeeze_long_only.py -q
#   git add backend/ memory/ && git commit -m "v358: daily_squeeze long-only (short branch is -EV)" && git push origin main
#   ./start_backend.sh --force
# ---------------------------------------------------------------------------
import base64
import hashlib
import shutil
import sys

FILE = "backend/services/enhanced_scanner.py"

PRE_FILE_SHA = "36067838a2bf786444b825b81d0e328626be8fcbad74ba712fd33ae792d9c182"

OLD_B64 = ""

NEW_B64 = ""


def main():
    check = "--check" in sys.argv
    src = open(FILE, encoding="utf-8").read()
    cur_sha = hashlib.sha256(src.encode("utf-8")).hexdigest()
    print(f"file            : {FILE}")
    print(f"live SHA        : {cur_sha}")
    print(f"expected SHA    : {PRE_FILE_SHA}")
    if cur_sha != PRE_FILE_SHA:
        print("\nABORT: live file SHA != expected baseline. The DGX file has DRIFTED.")
        print("Re-run extract_func.py _check_daily_squeeze and rebase. NOTHING was written.")
        sys.exit(2)

    old = base64.b64decode(OLD_B64).decode("utf-8")
    new = base64.b64decode(NEW_B64).decode("utf-8")
    n = src.count(old)
    print(f"OLD anchor count: {n}  (MUST be 1)")
    if n != 1:
        print("\nABORT: OLD anchor not uniquely found. NOTHING was written.")
        sys.exit(3)

    patched = src.replace(old, new, 1)
    post_sha = hashlib.sha256(patched.encode("utf-8")).hexdigest()
    if patched.count(new) != 1 or old in patched:
        print("\nABORT: post-replace self-check failed. NOTHING was written.")
        sys.exit(4)
    print(f"POST SHA        : {post_sha}")

    if check:
        print("\n--check OK: guards pass, OLD found exactly once, replacement is clean.")
        print("Run without --check to apply.")
        return

    bak = FILE + ".v358.bak"
    shutil.copy2(FILE, bak)
    with open(FILE, "w", encoding="utf-8") as f:
        f.write(patched)
    verify = hashlib.sha256(open(FILE, encoding="utf-8").read().encode("utf-8")).hexdigest()
    if verify != post_sha:
        print(f"\nABORT: post-write verify mismatch ({verify} != {post_sha}).")
        sys.exit(5)
    print(f"\nAPPLIED. backup -> {bak}")
    print(f"new live SHA    : {verify}")
    print("Next: pytest -> commit -> ./start_backend.sh --force")


if __name__ == "__main__":
    main()
